import{_ as l,o as i,c as e,a0 as t}from"./chunks/framework.CSGB4SNl.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/八股文day02.md","filePath":"java/eight-legged essay/八股文day02.md"}'),o={name:"java/eight-legged essay/八股文day02.md"};function r(s,a,n,c,h,d){return i(),e("div",null,[...a[0]||(a[0]=[t('<h4 id="aqs" tabindex="-1">AQS <a class="header-anchor" href="#aqs" aria-label="Permalink to &quot;AQS&quot;">​</a></h4><ol><li>aqs是针对于多线程相关的一个抽象框架，给继承此框架的类提供一套唤醒等待等机制</li><li>包括status资源状态每个子类实现不同，一个基于双向链表实现的fifo先进先出的同步队列</li><li>过程：先CAS去改status获取资源，失败则包装成一个Node节点然后打包进等待队列挂起，等待获取到资源的线程释放资源后进行唤醒</li><li>它定义了如何获取、唤醒、阻塞等待等，子类只要实现他的tryR什么的方法，告诉AQS什么样算获取到资源，什么样算释放资源等</li><li>主要有独占模式和共享模式，顾名思义，独占只能一个线程同时持有资源，共享n个线程同时持有资源，status一个对应重入次数，一个对应那个n包括剩余的</li></ol><h4 id="reentrantlock" tabindex="-1">ReentrantLock <a class="header-anchor" href="#reentrantlock" aria-label="Permalink to &quot;ReentrantLock&quot;">​</a></h4><ol><li><p>与synchronized区别，一个无需关系上锁和解锁jvm自动管理，一个需要手动进行上锁解锁lock/unlock，一个适用于不那么复杂场景，一个适用于复杂场景，两者都是可重入锁</p></li><li><p>jdk1.5开始引入的</p></li><li><p>它是非公平锁，就是获取到锁不必按照队列顺序，可以强制cas抢锁，这样性能更高，因为不必去唤醒某一个线程，减少上下文之类的开销</p></li><li><p>可重入锁，就是一个线程可以多次获取统一把锁，这样减少不必要的获取锁的开销，也不会说又得去排队把自己阻塞掉，会有个类似使用记录</p></li><li><p>获取锁-》cas去改status，改为1表示占有，释放时减一，变为0时唤醒等待队列中的线程</p></li><li><p>自旋锁的移除，设计不合理会导致总线风暴，后改为chl锁关注自己队列中前一位的状态，是否释放，就是排队拿锁了，那么这个过程是前面的来唤醒的，合理的睡一会就不会那么多来抢,也对应为啥使用双向链表</p></li><li><p>单项链表的话如果想要摘除掉某个超时的节点的话的从头开始，双向的话就很好支持通过一个查找到前一个和后一个</p></li><li><p>satus用int类型就可以支持一个线程多次重入，结束后也会释放对应次数，也支持开关这样的，比较通用</p></li></ol><h4 id="cas" tabindex="-1">CAS <a class="header-anchor" href="#cas" aria-label="Permalink to &quot;CAS&quot;">​</a></h4><ol><li>他是cpu级别的操作，用于比较变量是否是其的预期值(预期值是在执行操作前先找到变量存一次)，如果不是就不动，是则更新为新值</li><li>三个操作数-条件，变量的内存地址、旧的预期值，新值</li><li>如版本号，当然最简单的方式也可以是在mysql那边加版本号实现类似操作，本质思路都一样</li><li>自旋等待，自旋锁，就是不去休眠一直循环等待拿锁，一直失败呢，可设置次数上限或随机等待时间，或者改用其它，然后就是上限后降级，但是一般后者cas都有配备，会自动降为重量级锁</li><li>ABA问题cas无法感知过程，加版本号或时间戳</li><li>偏向锁是记录得来的，就是一个线程长期占有这个锁，那么这个锁就会去记录，下次拿锁时优先/偏向先给到它</li><li>总线风暴，就是有个广播器，当一个线程去修改工作内存，lock指令会把缓冲区的立即写入主存中，然后广播给其它线程，其它线程再从主存中读取</li></ol><h4 id="常用集合" tabindex="-1">常用集合 <a class="header-anchor" href="#常用集合" aria-label="Permalink to &quot;常用集合&quot;">​</a></h4><ol><li>Collection和map，一个存单列数据，一个存键值对双列数据</li><li>其中Collection有List(ArrayList、LinkedList-双向链表-也实现了Queue接口、也算小队列)、Set(HashSet-无序、LinkedHashSet-链表、TreeSet红黑树大小排序)、Queue队列(优先级队列-按大小出队)</li><li>Map有HasMap、TreeMap、LinkedHashMap、CuncurrentHashMap(线程安全)、HashTable(线程安全)</li></ol><h4 id="异常" tabindex="-1">异常 <a class="header-anchor" href="#异常" aria-label="Permalink to &quot;异常&quot;">​</a></h4><ol><li>编译时异常和运行时异常，编译时异常编译器要求强制处理、运行时异常可以不处理</li><li>父类Throwable，下面有Error和Exception，Error表示错误，程序无法处理，如栈溢出，Exception表示异常代码bug</li><li>Exception下面RuntimeException-运行时异常不强制和其它Exception-编译时异常必须处理，RuntimeException(空指针、下标越界)</li><li>编译时异常包括io异常、sql异常等</li></ol><h4 id="序列化和反序列化" tabindex="-1">序列化和反序列化 <a class="header-anchor" href="#序列化和反序列化" aria-label="Permalink to &quot;序列化和反序列化&quot;">​</a></h4><ol><li>序列化是将java代码转成二进制字节流，存到硬盘和传输到其它机器中，反序列化就是将字节流转成java对象</li><li>方式1类实现Serializable关键字，方式2如密码等敏感字段变量加上transient关键字，序列化的时候就会跳过,方式3显式定义serialVersionUID给类打上版本号，防止改了类之后反序列化旧数据时报错</li></ol>',12)])])}const _=l(o,[["render",r]]);export{u as __pageData,_ as default};
